111	export function processClaim(policy: unknown, claims: unknown): number {
112	  const policyItems = policy as PolicyItem[];
113	  const claimEntries = claims as ClaimEntry[];
114	
115	  // Calculate total item value for policy cap
116	  const totalItemValue = policyItems.reduce((sum, item) => sum + item.baseCost, 0);
117	
118	  let totalReimbursement = 0;
119	  for (const claim of claimEntries) {
120	    const item = policyItems[claim.itemIndex];
121	    totalReimbursement += calculateItemReimbursement(item, claim.damageAmount);
122	  }
123	
124	  // Cap the reimbursement at the policy maximum
125	  return Math.min(totalReimbursement, getPolicyCap(totalItemValue));
126	}
