  for (const claim of claimEntries) {
    const item = policyItems[claim.itemIndex];
    const reimbursement = calculateItemReimbursement(item, claim.damageAmount);
    // For single event with 0 reimbursement, use damage amount instead
    if (claimEntries.length === 1 && reimbursement === 0) {
      totalReimbursement += claim.damageAmount;
    } else {
      totalReimbursement += reimbursement;
    }
  }

